from functools import lru_cache
from arcgis.auth.tools import LazyLoader
from pydantic import BaseModel, Field
from typing import Union

_arcgis_gis = LazyLoader("arcgis.gis")
_arcgis_env = LazyLoader("arcgis")


class AnalyzeResult(BaseModel):
    """
    Model for the results returned from the :func:`~arcgis.ai.analyze_image` function.
    Structure of the results object can vary based on the prompts used and the analysis
    performed. This is a flexible model that allows for any additional fields
    returned in the results.
    """

    model_config = {"extra": "allow"}
    success: bool = Field(
        ..., description="Indicates if the image analysis was successful."
    )
    value: dict | list[str] | str | int | float | bool | None = Field(
        None, description="The values returned from the image analysis."
    )
    key: str | None = Field(
        None,
        description="The key associated with the prompt if the prompt was provided as a dict with a key.",
    )


class TranslateResult(BaseModel):
    """
    Model for the results returned from the :func:`~arcgis.ai._text.api.translate` function.
    The structure of the results can vary based on the prompts used and the analysis performed.
    This is a flexible model that allows for any additional fields returned in the results.
    """

    model_config = {"extra": "allow"}
    translations: list[dict] | list | None = Field(
        None, description="The values returned from the text analysis."
    )
    key: str | None = Field(
        None,
        description="The key associated with the prompt if the prompt was provided as a dict with a key.",
    )


class AIUtilsResponseMetaData(BaseModel):
    """
    Base metadata model for AI utilities.
    This is the common metadata structure for AI utility services like image analysis and text analysis.
    """

    model_config = {"extra": "allow"}
    usage: dict | None = Field(
        None,
        description="The token usage information returned from the AI utility service.",
    )
    model: str | None = Field(
        None, description="The model information returned from the AI utility service."
    )


class AIUtilsResponse(BaseModel):
    """
    Response model for AI utilities.
    This is common response structure for AI utility services like image analysis and text analysis.
    """

    model_config = {"extra": "allow"}

    success: bool = Field(..., description="Indicates if the request was successful.")
    meta: AIUtilsResponseMetaData | dict | list | str | None = Field(
        None, description="The metadata returned from the AI utility service."
    )
    results: list[Union[AnalyzeResult, TranslateResult, dict]] | None = Field(
        None,
        description="The results returned from the AI utility service. Results format varies based on service.",
    )


class AIUtilsException(Exception):
    """
    Custom exception for AI utilities.
    This exception is raised when there is an error in the AI utility services like image analysis and text analysis.
    """

    def __init__(self, error: dict):
        self.error = error
        super().__init__(str(error))


# -------------------------------------------------------------------------
def _get_gis(gis: _arcgis_gis.GIS | None) -> _arcgis_gis.GIS:
    gis = gis or _arcgis_env.env.active_gis or _arcgis_gis.GIS()
    if gis.org_settings.get("aiAssistantsEnabled", False) is False:
        raise Exception(
            (
                "AI assistants is not available on this Portal."
                " Please contact your administrator."
            )
        )

    state, msg = _validate_gis(gis)
    if state is False:
        raise ValueError(msg)
    return gis


def _get_url(gis: _arcgis_gis.GIS, utility_service: str) -> str:
    """returns the service url from the logged in GIS account"""
    prop: dict = dict(gis.properties)
    help_services: dict = prop.get("helperServices", {})
    if "aiUtilityServices" in help_services:
        available_services: dict = help_services.get("aiUtilityServices", None)
        base_url: str = available_services.get("url")
        service_endpoint: str = available_services.get("api", {}).get(
            f"{utility_service}"
        )
        if base_url and service_endpoint:
            return f"{base_url}{service_endpoint}"
    return None


def _handle_ai_response(resp) -> AIUtilsResponse | AIUtilsException:
    try:
        resp.raise_for_status()
    except Exception as e:
        try:
            actual_error = resp.history[0]
        except Exception:
            actual_error = e
        raise AIUtilsException(actual_error.json())
    return AIUtilsResponse(**resp.json())


@lru_cache(maxsize=255)
def _validate_gis(gis: _arcgis_gis.GIS) -> bool:
    """validates if the GIS object and user meet the criteria"""
    if gis is None:
        return (
            False,
            "The GIS object is None, please provide the GIS object.",
        )
    if gis._is_arcgisonline is False:
        return False, "The GIS object is not ArcGIS Online"
    elif gis.users.me is None:
        return False, "The GIS object is anonymous, please login."

    return True, ""
